import { createContext, useContext, useReducer } from "react"
const ReviewsContext = createContext()
// submitStatus -> success/error
const SUBMIT_STATUS = {
    SUCCESS: 'success',
    ERROR: 'error'
}

const INITIAL_STATE = {
    formData: {
        reviewText: '',
        title: '',
        rating: 0,
        submitStatus: 'succ'
    },
    reviews: []
}

export const ACTIONS = {
    SAVE_FORM: 'SAVE_FORM',
    UPDATE_REVIEWS: 'UPDATE_REVIEWS',
}

export function reducer(state = INITIAL_STATE, action) {
    switch (action.type) {
        case ACTIONS.SAVE_FORM: {
            return {
                ...state,
                formData: { ...state.formData, ...action.data.formData },
                reviews: [...state.reviews, { ...state.formData }]
            }
        }
        case ACTIONS.UPDATE_REVIEWS: {
            return {
                ...state,
                reviews: [...state.reviews, { ...state.formData }]
            }
        }
    }
}

export function ReviewsProvider({ children }) {
    const [state, dispatch] = useReducer(reducer, { ...INITIAL_STATE })
    const saveForm = (formData) => {
        dispatch({
            type: ACTIONS.SAVE_FORM,
            data: {
                formData
            }
        })
    }
    const value = {
        ...state,
        saveForm
    }
    return <ReviewsContext.Provider value={value}>
        {children}
    </ReviewsContext.Provider>
}

export function useReviewsContext() {
    return useContext(ReviewsContext)
}
